void carregar_mapa() {

        ts_dungeon = LoadTexture("assets/tilesets_dungeon.png");
        ts_bau = LoadTexture("assets/tilesets_bau.png");
        ts_papeis = LoadTexture("assets/tilesets_papeis.png");
}

void descarregar_mapa() {

        UnloadTexture(ts_dungeon);
        UnloadTexture(ts_bau);
        UnloadTexture(ts_papeis);
}

static Texture2D get_texture(int id) {

        if(id == ID_PAREDE) return ts_dungeon;
        if(id == ID_CHAO_CENTRO) return ts_dungeon;
        if(id == ID_BAU) return ts_bau;
        if(id == ID_PAPEIS)  return ts_papeis;
        if(id == ID_PORTA_BAIXO)   return ts_dungeon;
        if(id == ID_PORTA_CIMA)  return ts_dungeon;
}


static Rectangle get_origem(int id){

        if(id == ID_PAREDE) return (Rectangle)  {96, 208, TILE, TILE};
        if(id == ID_CHAO_CENTRO) return (Rectangle) {64, 64, TILE, TILE};
        if(id == ID_BAU)  return (Rectangle) {32, 0, TILE, TILE};
        if(id == ID_PAPEIS)  return (Rectangle) {192, 160, TILE, TILE};
        if(id == ID_PORTA_BAIXO)   return (Rectangle) {160, 112, TILE, TILE};
        if(id == ID_PORTA_CIMA)  return (Rectangle) {160, 96, TILE, TILE};

}

void desenhar_mapa() {

        for(int i= 0; i < LINHA; i++ ) {

            for(int j= 0; j < COLUNA; j++){
                int id = mapa[i][j];

                if(id == 0){
                    continue;
                }

                int x = j * TILE;
                int y = i * TILE;

                Texture2D tex = get_texture(id);
                Rectangle origem = get_origem(id);
                Vector2 pos = {(float)x, (float)y};
                DrawTextureRec(tex, origem, pos, WHITE);
            }
        }

}


int get_tile(int linha, int coluna){
    if(linha < 0 || linha >= LINHA || coluna < 0 || coluna >= COLUNA)
        return ID_PAREDE;
        return mapa[LINHA][COLUNA];
    

}

int is_parede(int linha, int coluna) {
    return get_tile(linha, coluna) == ID_PAREDE;
}